// Before: one long method doing several things.
function printReport(orders) {
  let total = 0;
  for (const o of orders) total += o.amount;
  console.log('=== Report ===');
  for (const o of orders) console.log(`${o.id}: ${o.amount}`);
  console.log(`Total: ${total}`);
  console.log(`Avg: ${total / orders.length}`);
}

// After: each step is a named, testable function.
function printReport(orders) {
  printHeader();
  printLines(orders);
  printSummary(orders);
}
function printHeader() { console.log('=== Report ==='); }
function printLines(orders) {
  for (const o of orders) console.log(`${o.id}: ${o.amount}`);
}
function total(orders) { return orders.reduce((s, o) => s + o.amount, 0); }
function printSummary(orders) {
  const t = total(orders);
  console.log(`Total: ${t}`);
  console.log(`Avg: ${t / orders.length}`);
}

