function speed(bird) {
  switch (bird.type) {
    case 'european': return 35;
    case 'african':  return 40 - 2 * bird.numberOfCoconuts;
    case 'norwegian-blue':
      return bird.isNailed ? 0 : 10 + bird.voltage / 10;
    default: return null;
