}

// After: each variant owns its behavior; adding a species adds a class.
class Bird { speed() { return null; } }
class European extends Bird { speed() { return 35; } }
class African extends Bird {
  constructor(coconuts) { super(); this.coconuts = coconuts; }
  speed() { return 40 - 2 * this.coconuts; }
}
class NorwegianBlue extends Bird {
  constructor(nailed, voltage) { super(); this.nailed = nailed; this.voltage = voltage; }
  speed() { return this.nailed ? 0 : 10 + this.voltage / 10; }
}

