// Step 0: the tangled starting point (no place to hang a discount).
function checkout(cart) {
  let total = 0;
  for (const item of cart.items) total += item.price * item.qty;
  if (cart.country === 'US') total *= 1.0;
  else if (cart.country === 'DE') total *= 1.19;
  return total;
}

// Step 1 (refactor, behavior PRESERVED): extract the two concerns.
function subtotal(cart) {
  return cart.items.reduce((s, i) => s + i.price * i.qty, 0);
}
function withTax(amount, country) {
  const rate = country === 'DE' ? 1.19 : 1.0;
  return amount * rate;
}
function checkout(cart) {
  return withTax(subtotal(cart), cart.country); // same result as before
}

// Step 2 (the easy change): the discount is now a one-line insertion.
