  const off = { gold: 0.10, silver: 0.05 }[tier] ?? 0;
  return amount * (1 - off);
}
function checkout(cart) {
  const discounted = applyLoyalty(subtotal(cart), cart.loyaltyTier);
  return withTax(discounted, cart.country);
}

challenges.prompt:
You are given a function that computes monthly pay using a switch over employee type, and the same switch shape is duplicated in three other functions (vacation days, bonus eligibility). Refactor `monthlyPay` to use Replace Conditional with Polymorphism so that adding a new employee type is a new class, not an edit to every switch. Behavior must be preserved: ENGINEER = base, MANAGER = base * 1.2, CONTRACTOR = base (no benefits). Original:

function monthlyPay(emp) {
  switch (emp.type) {
    case 'ENGINEER':   return emp.base;
    case 'MANAGER':    return emp.base * 1.2;
    case 'CONTRACTOR': return emp.base;
    default: throw new Error('unknown type');
  }
}

challenges.solutionCode:
// Each variant owns its own behavior — no switch anywhere.
class Employee {
  constructor(base) { this.base = base; }
  monthlyPay() { throw new Error('abstract'); }
}

class Engineer extends Employee {
  monthlyPay() { return this.base; }
}

class Manager extends Employee {
  monthlyPay() { return this.base * 1.2; }
}

class Contractor extends Employee {
  monthlyPay() { return this.base; }
}

// Factory keeps legacy callers (which pass {type, base}) working,
// isolating the ONE remaining place that knows about type strings.
const REGISTRY = {
  ENGINEER: Engineer,
  MANAGER: Manager,
  CONTRACTOR: Contractor,
};

function toEmployee(emp) {
  const Cls = REGISTRY[emp.type];
  if (!Cls) throw new Error('unknown type');
  return new Cls(emp.base);
}

// Backwards-compatible wrapper: same signature, same results as before.
function monthlyPay(emp) {
  return toEmployee(emp).monthlyPay();
}

// Adding INTERN is now a new class + one registry line; monthlyPay,
// vacationDays, and bonusEligible are never touched again.
class Intern extends Employee {
  monthlyPay() { return this.base * 0.5; }
}
REGISTRY.INTERN = Intern;

// --- quick behavior-preservation check (characterization) ---
// monthlyPay({type:'ENGINEER',   base:100}) === 100
// monthlyPay({type:'MANAGER',    base:100}) === 120
// monthlyPay({type:'CONTRACTOR', base:100}) === 100

challenges.prompt:
You inherit an untested legacy function `priceOrder(qty, unitPrice, customerTier)` whose logic is tangled but in production. Before you can refactor it, write characterization tests that pin its CURRENT behavior, then perform a behavior-preserving Extract Method refactor that separates the discount calculation from the total. Legacy code:

function priceOrder(qty, unitPrice, customerTier) {
  let total = qty * unitPrice;
  if (customerTier === 'gold') total = total - total * 0.10;
  else if (customerTier === 'silver') total = total - total * 0.05;
  if (qty >= 100) total = total - total * 0.02; // bulk, stacks on tier
  return Math.round(total * 100) / 100;
}

challenges.solutionCode:
// ---- Step 1: characterization tests (pin CURRENT behavior) ----
// Computed by hand from the legacy code, asserted exactly.
//   no tier, no bulk:   10 * 5            = 50.00
//   gold:               50 * 0.90         = 45.00
//   silver:             50 * 0.95         = 47.50
//   bulk only (qty100): 100*5=500; *0.98  = 490.00
//   gold + bulk:        500*0.90=450; *0.98 = 441.00
import { describe, it, expect } from 'vitest';

describe('priceOrder characterization', () => {
  it('no tier, below bulk', () => expect(priceOrder(10, 5, 'none')).toBe(50));
  it('gold tier',          () => expect(priceOrder(10, 5, 'gold')).toBe(45));
  it('silver tier',        () => expect(priceOrder(10, 5, 'silver')).toBe(47.5));
  it('bulk boundary at 100',() => expect(priceOrder(100, 5, 'none')).toBe(490));
  it('gold stacks with bulk',() => expect(priceOrder(100, 5, 'gold')).toBe(441));
  it('just below bulk',    () => expect(priceOrder(99, 5, 'none')).toBe(495));
});

// ---- Step 2: behavior-preserving Extract Method refactor ----
function tierRate(tier) {
  if (tier === 'gold') return 0.10;
  if (tier === 'silver') return 0.05;
  return 0;
}

function bulkRate(qty) {
  return qty >= 100 ? 0.02 : 0;
}

function priceOrder(qty, unitPrice, customerTier) {
  let total = qty * unitPrice;
  total = total - total * tierRate(customerTier); // same math, named
  total = total - total * bulkRate(qty);          // bulk still stacks after tier
  return Math.round(total * 100) / 100;
}
// Re-running the Step 1 tests: all still green -> behavior preserved.
